import LocalAuthentication

class AuthenticationManager {
    var context = LAContext()

    func authenticate(success: @escaping () -> Void) throws{
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil) else {
            throw AuthenticationError.biometricNotSupported
        }

        let reason = "Authentication is required to proceed"
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { _, result in
            switch result{
                case .success(_):
                    success()
                case .failure(let error):
                    print(error.localizedDescription)
                    throw AuthenticationError.failedToAuthenticate
            }

        }
    }
}

enum AuthenticationError : Error {
    case biometricNotSupported
    case failedToAuthenticate
}

